import React from "react";

export default function Filters({ filters, setFilters, options }) {

  const toggleFilter = (value) => {
    setFilters((prev) =>
      prev.includes(value)
        ? prev.filter((f) => f !== value)
        : [...prev, value]
    );
  };

  return (
    <div style={styles.container}>
      {options.map((opt) => {
        const active = filters.includes(opt);

        return (
          <button
            key={opt}
            onClick={() => toggleFilter(opt)}
            style={{
              ...styles.button,
              ...(active ? styles.active : {}),
            }}
          >
            {opt}
          </button>
        );
      })}
    </div>
  );
}

const styles = {
  container: {
    display: "flex",
    flexWrap: "wrap",
    gap: "8px",
    padding: "10px 20px",
  },
  button: {
    padding: "6px 10px",
    borderRadius: "6px",
    border: "1px solid rgba(255,255,255,0.3)",
    background: "rgba(255,255,255,0.15)",
    color: "#fff",
    fontSize: "12px",
    cursor: "pointer",
    transition: "all 0.2s ease",
  },
  active: {
    background: "#fff",
    color: "#333",
  },
};
